def tally_votes(votes):
    counts = {}
    for v in votes:
        counts[v] = counts.get(v, 0) + 1
    return max(counts, key=counts.get)

def run_practice():
    votes = ['option_A', 'option_B', 'option_A']
    assert tally_votes(votes) == 'option_A'
    print('[PASS] Consensus voting tally checks completed.')

if __name__ == '__main__':
    run_practice()
